-- CAR (Cordillera): Abra, Benguet, Ifugao, Kalinga, Apayao, Mountain Province
-- BIR RDO 7(Abra),8(Baguio)+9(Benguet),10(Mt.Province),11(Kalinga+Apayao split),12(Ifugao). Newest-DO-year-wins.
START TRANSACTION;
DELETE FROM zonal_values WHERE province IN ('ABRA','BENGUET','MOUNTAIN PROVINCE','KALINGA','APAYAO','IFUGAO');
COMMIT;
